package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.PrintStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private final PrintStream originalOut = System.out;
    private ByteArrayOutputStream testOut;

    @BeforeEach
    void setUp() {
        testOut = new ByteArrayOutputStream();
        System.setOut(new PrintStream(testOut));
    }

    @AfterEach
    void tearDown() {
        System.setOut(originalOut);
    }

    @Test
    void testPrinterReturnsCSVPrinterWithSystemOutAndThisFormat() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT.withAutoFlush(true);
        CSVPrinter printer = format.printer();
        assertNotNull(printer);
        String testString = "test";
        printer.print(testString);
        printer.flush();
        String output = testOut.toString();
        assertTrue(output.contains(testString));
    }
}
